import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as n,o as t,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Afbeeldingsmoderatie en toegangsmodus","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Safety/image-moderation-and-access-mode.md","filePath":"nl-NL/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"nl-NL/Safety/image-moderation-and-access-mode.md"};function r(l,e,s,g,p,b){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="afbeeldingsmoderatie-en-toegangsmodus" tabindex="-1">Afbeeldingsmoderatie en toegangsmodus <a class="header-anchor" href="#afbeeldingsmoderatie-en-toegangsmodus" aria-label="Permalink to &quot;Afbeeldingsmoderatie en toegangsmodus&quot;">​</a></h1><p>Afbeeldingsmoderatie geeft geüploade afbeeldingen een leeftijdsclassificatie. De toegangsmodus bepaalt welke classificaties openbaar zichtbaar zijn.</p><p>Dit beïnvloedt de openbare gallery, openbare bestands-URL&#39;s en de Random Image API. Het beperkt het beheerpaneel niet. Beheerders kunnen alle bestanden blijven bekijken en beheren.</p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open het beheer en ga naar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>De belangrijkste instellingen zijn:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="wat-access-mode-doet" tabindex="-1">Wat Access Mode doet <a class="header-anchor" href="#wat-access-mode-doet" aria-label="Permalink to &quot;Wat Access Mode doet&quot;">​</a></h2><p>Access mode bepaalt welke leeftijdsclassificaties openbaar getoond mogen worden.</p><p>Huidige modi:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Openbaar zichtbare ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Alleen General</td></tr></tbody></table><p>De standaardmodus is Adult mode.</p><p>Voor privésites of sites met volwassen inhoud kan Adult mode passend zijn. Voor een voorzichtiger openbare gallery kies je Youth, Teen of Child mode.</p><h2 id="wat-moderatie-inschakelen-doet" tabindex="-1">Wat moderatie inschakelen doet <a class="header-anchor" href="#wat-moderatie-inschakelen-doet" aria-label="Permalink to &quot;Wat moderatie inschakelen doet&quot;">​</a></h2><p>Wanneer moderatie is ingeschakeld, roept ImgBed tijdens upload de gekozen provider aan en slaat de gevonden leeftijdsclassificatie op.</p><p>Belangrijkste ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Betekenis</th></tr></thead><tbody><tr><td>General</td><td>Veilige openbare inhoud</td></tr><tr><td>R12</td><td>Licht gevoelige inhoud</td></tr><tr><td>R16</td><td>Matig gevoelige inhoud</td></tr><tr><td>R18</td><td>Volwassen inhoud</td></tr></tbody></table><p>Het moderatieresultaat wordt gebruikt bij het bepalen van openbare toegang.</p><p>Als moderatie niet is ingeschakeld, of oude bestanden geen rating hebben, worden die bestanden als niet-geclassificeerd behandeld. Niet-geclassificeerde bestanden worden niet automatisch uit de openbare gallery of Random Image API verwijderd alleen omdat er geen rating bestaat.</p><h2 id="een-moderatieprovider-kiezen" tabindex="-1">Een moderatieprovider kiezen <a class="header-anchor" href="#een-moderatieprovider-kiezen" aria-label="Permalink to &quot;Een moderatieprovider kiezen&quot;">​</a></h2><p>Beschikbare providers zijn onder meer:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Elke provider heeft eigen vereisten:</p><ul><li>moderatecontent.com vraagt meestal om een API Key.</li><li>nsfwjs vraagt meestal om een API-endpoint-URL.</li><li>Sightengine vereist een API user en API secret.</li></ul><p>Kies op basis van je account, beschikbaarheid en detectiekwaliteit. Zolang moderatie ingeschakeld en correct ingesteld is, probeert ImgBed tijdens upload een rating op te slaan.</p><h2 id="effect-op-de-openbare-gallery" tabindex="-1">Effect op de openbare gallery <a class="header-anchor" href="#effect-op-de-openbare-gallery" aria-label="Permalink to &quot;Effect op de openbare gallery&quot;">​</a></h2><p>De openbare gallery filtert bestanden volgens de toegangsmodus.</p><p>Voorbeelden:</p><ul><li>Adult mode: R18-afbeeldingen kunnen verschijnen.</li><li>Youth mode: R18-afbeeldingen worden verborgen.</li><li>Teen mode: R16- en R18-afbeeldingen worden verborgen.</li><li>Child mode: alleen General-afbeeldingen worden getoond.</li></ul><p>Dit geldt alleen voor normale openbare toegang. Het beheerpaneel toont nog steeds alle bestanden.</p><h2 id="effect-op-openbare-bestands-url-s" tabindex="-1">Effect op openbare bestands-URL&#39;s <a class="header-anchor" href="#effect-op-openbare-bestands-url-s" aria-label="Permalink to &quot;Effect op openbare bestands-URL&#39;s&quot;">​</a></h2><p>Openbare bestands-URL&#39;s zijn directe afbeeldingslinks die bezoekers openen.</p><p>Als de rating van het bestand is toegestaan door de huidige toegangsmodus, geeft ImgBed de oorspronkelijke afbeelding terug.</p><p>Is de rating hoger dan toegestaan, dan geeft normale openbare toegang niet de oorspronkelijke afbeelding terug. ImgBed geeft dan de ingestelde geblokkeerde uitvoer of vervangende afbeelding terug.</p><p>Voorbeeld:</p><ul><li>De huidige modus is Child mode.</li><li>Een afbeelding heeft rating R18.</li><li>Een bezoeker opent de openbare URL direct.</li><li>ImgBed geeft de oorspronkelijke R18-afbeelding niet terug aan die bezoeker.</li></ul><p><img src="'+a+'" alt="Beperkte bestandsafbeelding" loading="lazy"></p><p>Beheerders die bestanden in het beheerpaneel bekijken, worden niet door deze beperking geraakt.</p><h2 id="effect-op-de-random-image-api" tabindex="-1">Effect op de Random Image API <a class="header-anchor" href="#effect-op-de-random-image-api" aria-label="Permalink to &quot;Effect op de Random Image API&quot;">​</a></h2><p>De Random Image API filtert de kandidaatpool ook volgens de toegangsmodus.</p><p>In Child mode worden willekeurige afbeeldingen alleen gekozen uit General-bestanden.</p><p>In Youth mode kunnen willekeurige afbeeldingen uit General, R12 en R16 komen, maar niet uit R18.</p><p>Zo kan de Random Image API de regels van de openbare gallery niet omzeilen.</p><h2 id="samenhang-met-lijstregels" tabindex="-1">Samenhang met lijstregels <a class="header-anchor" href="#samenhang-met-lijstregels" aria-label="Permalink to &quot;Samenhang met lijstregels&quot;">​</a></h2><p>Access mode is niet de enige openbare toegangsregel. Het werkt samen met allowlist- en blocklistregels.</p><p>Kort gezegd:</p><ul><li>Inhoud op de allowlist is eerst openbaar.</li><li>Inhoud op de blocklist kan niet direct door gewone bezoekers worden bekeken.</li><li>Inhoud die op geen van beide lijsten staat, wordt daarna gecontroleerd tegen access mode.</li></ul><p>Als een afbeelding zowel door leeftijdsrating als door lijstregels wordt beperkt, kunnen gewone bezoekers het oorspronkelijke bestand nog steeds niet direct bekijken.</p><h2 id="aanbevolen-instellingen" tabindex="-1">Aanbevolen instellingen <a class="header-anchor" href="#aanbevolen-instellingen" aria-label="Permalink to &quot;Aanbevolen instellingen&quot;">​</a></h2><p>Voor openbare sites:</p><ul><li>Schakel moderatie in.</li><li>Kies een toegangsmodus die past bij het publiek van de site.</li><li>Gebruik Child mode of Teen mode voor bezoekers van alle leeftijden.</li><li>Vermijd Adult mode als je volwassen inhoud niet openbaar wilt tonen.</li><li>Controleer ratings in het beheerpaneel en pas ze handmatig aan wanneer nodig.</li></ul><p>Voor privé- of persoonlijke sites:</p><ul><li>Adult mode is meestal prima.</li><li>Schakel moderatie in als het nuttig is.</li><li>Controleer en pas ratings in het beheerpaneel aan wanneer nodig.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="verdwijnen-bestanden-uit-het-beheerpaneel-als-ik-access-mode-wijzig" tabindex="-1">Verdwijnen bestanden uit het beheerpaneel als ik Access Mode wijzig? <a class="header-anchor" href="#verdwijnen-bestanden-uit-het-beheerpaneel-als-ik-access-mode-wijzig" aria-label="Permalink to &quot;Verdwijnen bestanden uit het beheerpaneel als ik Access Mode wijzig?&quot;">​</a></h3><p>Nee.</p><p>Access mode beïnvloedt alleen normale openbare toegang. Het heeft geen effect op het beheerpaneel.</p><h3 id="waarom-toont-de-openbare-gallery-minder-afbeeldingen-na-wisselen-naar-child-mode" tabindex="-1">Waarom toont de openbare gallery minder afbeeldingen na wisselen naar Child mode? <a class="header-anchor" href="#waarom-toont-de-openbare-gallery-minder-afbeeldingen-na-wisselen-naar-child-mode" aria-label="Permalink to &quot;Waarom toont de openbare gallery minder afbeeldingen na wisselen naar Child mode?&quot;">​</a></h3><p>Child mode staat alleen General-bestanden openbaar toe. R12, R16 en R18 worden weggefilterd.</p><h3 id="kunnen-openbare-url-s-nog-volwassen-afbeeldingen-openen" tabindex="-1">Kunnen openbare URL&#39;s nog volwassen afbeeldingen openen? <a class="header-anchor" href="#kunnen-openbare-url-s-nog-volwassen-afbeeldingen-openen" aria-label="Permalink to &quot;Kunnen openbare URL&#39;s nog volwassen afbeeldingen openen?&quot;">​</a></h3><p>Als de huidige toegangsmodus die rating niet toestaat, geven normale openbare URL&#39;s de oorspronkelijke afbeelding niet terug.</p><h3 id="kan-de-random-image-api-beperkte-afbeeldingen-teruggeven" tabindex="-1">Kan de Random Image API beperkte afbeeldingen teruggeven? <a class="header-anchor" href="#kan-de-random-image-api-beperkte-afbeeldingen-teruggeven" aria-label="Permalink to &quot;Kan de Random Image API beperkte afbeeldingen teruggeven?&quot;">​</a></h3><p>Nee.</p><p>De Random Image API filtert kandidaten volgens de huidige toegangsmodus.</p><h3 id="wat-gebeurt-er-met-oude-afbeeldingen-zonder-rating" tabindex="-1">Wat gebeurt er met oude afbeeldingen zonder rating? <a class="header-anchor" href="#wat-gebeurt-er-met-oude-afbeeldingen-zonder-rating" aria-label="Permalink to &quot;Wat gebeurt er met oude afbeeldingen zonder rating?&quot;">​</a></h3><p>Afbeeldingen zonder rating worden niet automatisch verborgen alleen omdat ze geen moderatieresultaat hebben. Je kunt hun rating later aanpassen in het beheerpaneel.</p>',67)])])}const u=n(d,[["render",r]]);export{c as __pageData,u as default};
